func newCmdAndroidHardwareSecuritySeeStorageIStorageSession_OpenDir() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "open-dir",
		Short: "Call OpenDir(path string, readIntegrity ReadIntegrity) -> IDir",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.hardware.security.see.storage.IStorageSession")
			}
			if err != nil {
				return err
			}

			svcProxy := storage.NewStorageSessionProxy(svc)

			flagPath, err := cmd.Flags().GetString("path")
			if err != nil {
				return fmt.Errorf("reading flag path: %w", err)
			}

			flagReadIntegrityRaw, err := cmd.Flags().GetInt32("readIntegrity")
			if err != nil {
				return fmt.Errorf("reading flag readIntegrity: %w", err)
			}
			flagReadIntegrity := storage.ReadIntegrity(flagReadIntegrityRaw)

			result, err := svcProxy.OpenDir(ctx, flagPath, flagReadIntegrity)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("result", result)
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().String("path", "", "path (string)")
	_ = cmd.MarkFlagRequired("path")
	cmd.Flags().Int32("readIntegrity", 0, "readIntegrity (ReadIntegrity enum)")
	_ = cmd.MarkFlagRequired("readIntegrity")

	return cmd
}
